args.ReplacementContent:
{/* Mobile Preview: Both Variants */}
<div className="md:hidden flex flex-col gap-8 mb-4 w-full">
  {/* VARIANT 1: Dropdown */}
  <div>
    <p className="text-xs text-slate-500 mb-2 font-bold uppercase tracking-wider">Вариант 1: Dropdown (Выпадающий список)</p>
    <div className="relative sticky top-16 z-40">
      <select 
        className="w-full bg-black/[0.03] dark:bg-white/5 border border-black/10 dark:border-white/10 rounded-xl px-4 py-3.5 appearance-none font-medium text-foreground focus:outline-none focus:border-indigo-500/50"
        value={activeHash}
        onChange={(e) => {
          window.history.pushState(null, '', `/profile/${e.target.value}`);
          window.dispatchEvent(new Event('hashchange'));
        }}
      >
        {profileTabs.map(tab => (
          <option key={tab.id} value={tab.href}>{tab.label}</option>
        ))}
      </select>
      <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none opacity-50">
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="m6 9 6 6 6-6"/></svg>
      </div>
    </div>
  </div>

  {/* VARIANT 2: Sticky Horizontal Scroll */}
  <div>
    <p className="text-xs text-slate-500 mb-2 font-bold uppercase tracking-wider">Вариант 2: Sticky Липкая Лента</p>
    <nav className="flex gap-2 overflow-x-auto no-scrollbar py-3 px-4 -mx-4 bg-background/95 backdrop-blur-md border-y border-black/5 dark:border-white/5 sticky top-16 z-40">
      {profileTabs.map((tab) => {
        const isActive = activeHash === tab.href;
        const Icon = tab.icon;
        return (
          <Link
            key={tab.id}
            href={`/profile/${tab.href}`}
            onClick={(e) => {
              if (isPremiumCylinder && window.location.pathname.startsWith('/profile')) {
                e.preventDefault();
                window.history.pushState(null, '', `/profile/${tab.href}`);
                window.dispatchEvent(new Event('hashchange'));
              }
            }}
            className={cn(
              "relative flex items-center gap-2 px-4 py-2.5 rounded-xl transition-colors whitespace-nowrap shrink-0",
              isActive ? "text-slate-900 dark:text-white bg-black/5 dark:bg-white/10" : "text-slate-500 dark:text-gray-400 border border-black/5 dark:border-white/5"
            )}
          >
            <Icon className="w-4 h-4 shrink-0" />
            <span className="font-medium text-sm">{tab.label}</span>
          </Link>
        );
      })}
    </nav>
  </div>
</div>

{/* Desktop Navigation */}
<nav className="hidden md:flex flex-col gap-2 w-64 shrink-0 sticky top-8 h-fit">
  {profileTabs.map((tab) => {
    const isActive = activeHash === tab.href;
    const Icon = tab.icon;

    return (
      <Link
        key={tab.id}
        href={`/profile/${tab.href}`}
        onClick={(e) => {
          if (isPremiumCylinder && window.location.pathname.startsWith('/profile')) {
            e.preventDefault();
            window.history.pushState(null, '', `/profile/${tab.href}`);
            window.dispatchEvent(new Event('hashchange'));
          }
        }}
        className={cn(
          "relative flex items-center gap-3 px-4 py-3 rounded-xl transition-colors",
          isActive ? "text-slate-900 dark:text-white" : "text-slate-500 dark:text-gray-400 hover:text-slate-900 dark:hover:text-gray-200 hover:bg-black/[0.03] dark:hover:bg-white/5"
        )}
      >
        {isActive && (
          <motion.div
            layoutId="profile-tab-active-desktop"
            className="absolute inset-0 bg-black/[0.05] dark:bg-white/10 border border-black/20 dark:border-white/20 rounded-xl"
            initial={false}
            transition={{ type: "spring", stiffness: 300, damping: 30 }}
          />
        )}
        <Icon className="w-5 h-5 relative z-10 shrink-0" />
        <span className="font-medium relative z-10 break-words leading-tight">{tab.label}</span>
      </Link>
    );
  })}
</nav>

